  "Q1_F14": {
    "question": "In the refrigerator/freezer section, what must you do with both appliance doors, and what reminder step goes with it?",
    "expectedAnswer": "Keep both doors closed as much as possible and tape a note to each door as a reminder."
  },
  "Q2_F10": {
    "question": "What kind of can opener must you make sure to own for the emergency food, and why?",
    "expectedAnswer": "make sure you own a manual can opener, because an electric one will be useless"
  },
  "Q3_F9": {
    "question": "Name the recommended non-perishable food choices for the emergency shelf.",
    "expectedAnswer": "canned beans, canned fish, peanut butter, crackers, dried fruit, and shelf-stable milk"
  },
  "Q4_F22": {
    "question": "At what indoor temperature, and under what condition, should you relocate, and to where?",
    "expectedAnswer": "If the indoor temperature falls below ten degrees Celsius and you cannot maintain warmth, relocate to a warming centre or a neighbour's home."
  },
  "Q5_F29": {
    "question": "When power returns, how long should you wait before switching major appliances back on, and why?",
    "expectedAnswer": "Wait five minutes before switching major appliances back on, so the grid can stabilise."
  },
  "Q6_F16": {
    "question": "What primary light source is recommended, and what light source should be avoided and why?",
    "expectedAnswer": "Use battery-powered LED lanterns or headlamps as your primary light source, and avoid candles entirely, since candles are a leading cause of house fires during outages."
  },
  "Q7_F28": {
    "question": "Which three phone numbers should you write down on paper, and why?",
    "expectedAnswer": "Write down the phone numbers of your pharmacy, your doctor, and the poison-control line on paper, because a dead phone is not a phone book."
  },
  "Q8_F2": {
    "question": "What climate is this guide written for, and what backup equipment does it assume you do not have?",
    "expectedAnswer": "It is written for a temperate climate and assumes no backup generator."
  }
